/* GuestToken.selectLatestGuestTokenBySocialAccountId */
SELECT ID, GUEST_ID, PARTNER_ID, GUEST_TOKEN, SOCIAL_ACCOUNT_ID, EXPIRE_DATE, CRE_TM
FROM TB_GUEST_TOKEN
WHERE SOCIAL_ACCOUNT_ID = #{socialAccountId}
ORDER BY CRE_TM DESC
LIMIT 1

